struct Node {
    int data;
    struct Node *next;
};

void traverse(struct Node *head) {
    struct Node *cur = head;
    while (cur != NULL) {
        printf("%d -> ", cur->data);
        cur = cur->next;
    }
    printf("NULL\n");
}

struct Node* insertFront(struct Node *head, int value) {
    struct Node *newNode = malloc(sizeof(struct Node));
    newNode->data = value;
    newNode->next = head;
    return newNode; // new head
}

struct Node* deleteValue(struct Node *head, int value) {
    struct Node *cur = head, *prev = NULL;
    while (cur != NULL && cur->data != value) {
        prev = cur;
        cur = cur->next;
    }
    if (cur == NULL) return head; // not found
    if (prev == NULL) head = cur->next; // deleting head
    else prev->next = cur->next;
    free(cur);
    return head;
}

struct DNode {
    int data;
    struct DNode *next;
    struct DNode *prev;
};

struct Node* reverse(struct Node *head) {
    struct Node *prev = NULL, *cur = head, *next;
    while (cur != NULL) {
        next = cur->next;
        cur->next = prev;
        prev = cur;
        cur = next;
    }
    return prev; // new head
}
